const express = require('express');
const axios = require('axios');
const app = express();
const port = 3000;

app.use(express.json());

app.all('*', async (req, res) => {
    const apiKey = req.query.api_key;
    if (!apiKey) {
        return res.status(401).send('API key is required');
    }

    const backendUrl = 'http://backend-service'; // Replace with actual backend URL
    const headers = { ...req.headers, 'X-API-Key': apiKey };

    try {
        const response = await axios({
            method: req.method,
            url: `${backendUrl}${req.url}`,
            headers,
            data: req.body
        });

        res.status(response.status).send(response.data);
    } catch (error) {
        console.error('Error forwarding request:', error.response ? error.response.data : error.message);
        res.status(error.response ? error.response.status : 500).send(error.response ? error.response.data : 'Internal Server Error');
    }
});

app.listen(port, () => {
    console.log(`API Gateway running on port ${port}`);
});